<script setup>import{onMounted,ref}from'vue';import axios from'axios';import PageHeader from'../components/PageHeader.vue';const data=ref({}),from=ref(new Date(new Date().getFullYear(),new Date().getMonth(),1).toISOString().slice(0,10)),to=ref(new Date().toISOString().slice(0,10)),search=ref('');async function load(){data.value=(await axios.get('/api/reports',{params:{from:from.value,to:to.value,search:search.value}})).data}onMounted(load);function csv(){const rows=[['NENIAL REPORT'],['From',from.value],['To',to.value],[],['Product','On hand','Reserved','Available'],...(data.value.inventory||[]).filter(p=>p.name.toLowerCase().includes(search.value.toLowerCase())).map(p=>[p.name,p.stock_quantity,p.reserved_quantity,p.available_quantity])];const blob=new Blob([rows.map(r=>r.map(v=>`"${v??''}"`).join(',')).join('\n')],{type:'text/csv'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='nenial-report.csv';a.click();URL.revokeObjectURL(a.href)}</script>
<template><PageHeader title="Company reports" subtitle="Daily, weekly, monthly, or custom operational reporting"><button class="btn primary" @click="csv">Download CSV</button></PageHeader><section class="panel filters"><label>From<input v-model="from" type="date"></label><label>To<input v-model="to" type="date"></label><label>Search<input v-model="search" placeholder="Product or detail"></label><button class="btn primary" @click="load">Apply</button></section><div class="stat-grid"><article class="stat"><span>Sales</span><strong>₱{{Number(data.sales?.total||0).toLocaleString()}}</strong><small>{{data.sales?.count||0}} transactions</small></article><article class="stat"><span>Payroll</span><strong>₱{{Number(data.payroll||0).toLocaleString()}}</strong><small>Net payroll finalized</small></article><article class="stat"><span>Inventory</span><strong>{{data.inventory?.length||0}}</strong><small>Tracked SKUs</small></article><article class="stat"><span>Order groups</span><strong>{{data.orders?.length||0}}</strong><small>Statuses in period</small></article></div><section class="panel table-wrap"><div class="panel-head"><h2>Inventory report</h2></div><table><thead><tr><th>Product</th><th>On hand</th><th>Reserved</th><th>Available</th><th>Value</th></tr></thead><tbody><tr v-for="p in (data.inventory||[]).filter(x=>x.name.toLowerCase().includes(search.toLowerCase()))" :key="p.id"><td>{{p.name}}</td><td>{{p.stock_quantity}}</td><td>{{p.reserved_quantity}}</td><td>{{p.available_quantity}}</td><td>₱{{(p.stock_quantity*p.price).toLocaleString()}}</td></tr></tbody></table></section></template>
